SELECT 
    er.*,
    c.id as comp_id, c.name as comp_name, c.formula as comp_formula, c.category as comp_category,
    p.id as proc_id, p.name as proc_name, p.process_type as proc_type, 
    p.temperature as proc_temperature, p.pressure as proc_pressure, p.duration as proc_duration,
    t.team_name
FROM experiment_records er
LEFT JOIN compositions c ON er.composition_id = c.id
LEFT JOIN processes p ON er.process_id = p.id
LEFT JOIN teams t ON er.team_id = t.id



        AND (
            er.title LIKE CONCAT('%', #{search.keyword}, '%')
            OR er.description LIKE CONCAT('%', #{search.keyword}, '%')
        )




        AND er.record_number LIKE CONCAT('%', #{search.recordNumber}, '%')




        AND er.status = #{search.status}




        AND er.team_id = #{search.teamId}




        AND er.composition_id = #{search.compositionId}




        AND er.process_id = #{search.processId}




        AND er.created_by = #{search.createdBy}




        AND er.experiment_date >= #{search.startDate}


        AND er.experiment_date <= #{search.endDate}




        AND p.temperature >= #{search.minTemperature}


        AND p.temperature <= #{search.maxTemperature}




        AND p.pressure >= #{search.minPressure}


        AND p.pressure <= #{search.maxPressure}




        AND EXISTS (
            SELECT 1 FROM properties prop
            WHERE prop.experiment_id = er.id
            AND prop.property_name = #{search.propertyName}

                AND prop.property_value >= #{search.minPropertyValue}


                AND prop.property_value <= #{search.maxPropertyValue}


                AND prop.property_type = #{search.propertyType}

        )






        ORDER BY 

            er.created_at
            er.experiment_date
            er.record_number
            er.title
            er.created_at


            ASC
            DESC
            DESC



        ORDER BY er.created_at DESC




LIMIT #{search.pageSize} OFFSET #{offset}

SELECT COUNT(DISTINCT er.id)
FROM experiment_records er
LEFT JOIN compositions c ON er.composition_id = c.id
LEFT JOIN processes p ON er.process_id = p.id
LEFT JOIN teams t ON er.team_id = t.id



        AND (
            er.title LIKE CONCAT('%', #{search.keyword}, '%')
            OR er.description LIKE CONCAT('%', #{search.keyword}, '%')
        )


        AND er.record_number LIKE CONCAT('%', #{search.recordNumber}, '%')


        AND er.status = #{search.status}


        AND er.team_id = #{search.teamId}


        AND er.composition_id = #{search.compositionId}


        AND er.process_id = #{search.processId}


        AND er.created_by = #{search.createdBy}


        AND er.experiment_date >= #{search.startDate}


        AND er.experiment_date <= #{search.endDate}


        AND p.temperature >= #{search.minTemperature}


        AND p.temperature <= #{search.maxTemperature}


        AND p.pressure >= #{search.minPressure}


        AND p.pressure <= #{search.maxPressure}


        AND EXISTS (
            SELECT 1 FROM properties prop
            WHERE prop.experiment_id = er.id
            AND prop.property_name = #{search.propertyName}

                AND prop.property_value >= #{search.minPropertyValue}


                AND prop.property_value <= #{search.maxPropertyValue}


                AND prop.property_type = #{search.propertyType}

        )

